#include <bits/stdc++.h>
using namespace std;
int A[4005], B[4005], C[4005];
int main() {
	string a, b;
	cin >> a >> b;
	for(int i = 0; i < a.size(); ++i)
		A[a.size() - i - 1] = a[i] - '0';
	for(int i = 0; i < b.size(); ++i)
		B[b.size() - i - 1] = b[i] - '0';
	for(int i = 0; i <= 2000; ++i) {
		for(int j = 0; j <= 2000; ++j) {
			C[i + j] += A[i] * B[j];
			C[i + j + 1] += C[i + j] / 10;
			C[i + j] %= 10;
		}
	}
	int f = 0;
	for(int i = 4000; i >= 0; --i) {
		if(C[i] != 0) f = 1;
		if(f == 1) cout << C[i];
	}
	if(f == 0) cout << 0;
	return 0;
}
